import { writeFileSync } from 'node:fs';

const generated = `// Auto-generated by scripts/inline-modern-monaco.mjs
// Do not edit manually.
interface PluginLike {
	manifest: { id: string; dir?: string };
	app: {
		plugins?: { manifests?: Record<string, { dir?: string }> };
		vault: { adapter: { basePath?: string; read(path: string): Promise<string> } };
	};
}

interface ManifestWithFallback {
	shikiModernMonacoFallback?: unknown;
}

type RequireLike = (id: string) => unknown;

export async function loadBundledModernMonacoSource(plugin: PluginLike, requireFn: RequireLike): Promise<string> {
	if (typeof DecompressionStream !== 'function') {
		throw new Error('DecompressionStream is unavailable for bundled modern-monaco fallback');
	}
	const manifestSource = await readPluginFile(plugin, requireFn, 'manifest.json');
	const manifest = JSON.parse(manifestSource) as ManifestWithFallback;
	const fallback = manifest.shikiModernMonacoFallback;
	if (typeof fallback !== 'string') {
		throw new Error('Bundled modern-monaco fallback payload was not found in manifest.json');
	}
	const binary = atob(fallback);
	const bytes = new Uint8Array(binary.length);
	for (let index = 0; index < binary.length; index++) {
		bytes[index] = binary.charCodeAt(index);
	}
	const stream = new Blob([bytes]).stream().pipeThrough(new DecompressionStream('gzip'));
	return new Response(stream).text();
}

async function readPluginFile(plugin: PluginLike, requireFn: RequireLike, fileName: string): Promise<string> {
	const appPlugins = plugin.app.plugins;
	const pluginDir = plugin.manifest.dir ?? appPlugins?.manifests?.[plugin.manifest.id]?.dir ?? '.obsidian/plugins/' + plugin.manifest.id;
	const adapterPath = pluginDir.split('\\\\').join('/') + '/' + fileName;
	try {
		return await plugin.app.vault.adapter.read(adapterPath);
	} catch {
		const fs = requireFn('fs') as { readFileSync(path: string, encoding: 'utf8'): string };
		const path = requireFn('path') as { isAbsolute(path: string): boolean; join(...parts: string[]): string };
		const vaultBasePath = plugin.app.vault.adapter.basePath ?? '';
		const pluginDirPath = path.isAbsolute(pluginDir) ? pluginDir : path.join(vaultBasePath, pluginDir);
		return fs.readFileSync(path.join(pluginDirPath, fileName), 'utf8');
	}
}
`;

writeFileSync('packages/obsidian/src/modern-monaco-inline.ts', generated);

console.log('Generated modern-monaco fallback loader');
